var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"케이스 37. 선별원 코드 B2-1.","JPN":"ケース37。選別人コードB2-1。","ENG":"Case 37. Subject code B2-1.","TWN":"案例編號，37。受試者代碼，B2-1。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"대상의 침식내성은 일반인을 조금 웃도는 수준이며, 비카운터로 분류된다.","JPN":"対象の侵食耐性は一般人を少し上回るレベルであり、非カウンターとして分類される。","ENG":"The subject's Corruption resistance is slightly above average and is classified as a non-Counter.","TWN":"實驗對象的侵蝕耐性略高於普通人，但仍舊被歸類為非制裁者。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"하지만 추출물 미드나잇 D타입에 부작용을 보이지 않은 유일한 케이스로, 일전에 시험한 6개 시약에 높은 반응성을 보였다.","JPN":"だが、抽出物ミッドナイトDタイプに副作用を見せなかった唯一のケースで、この前に試験した6つの試薬に高い反応性を見せた。","ENG":"However, she was the only subject who did not show any side effects to the extract Midnight Type D, while showing high responses to the 6 reagents tested previously.","TWN":"然而，作為唯一對午夜D型提取物沒有表現出副作用的案例，她對之前測試的6種試劑表現出極高的反應性。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"이번 테스트에선 시약을 대신해 혈액 샘플을 직접적으로 투여할 예정이다.","JPN":"今回のテストでは試薬の代わりに血液のサンプルを直接的に投与する予定だ。","ENG":"In this test, I will be administering the blood sample directly to her instead of a reagent.","TWN":"這次測試中我將直接為其注入血液樣本代替試劑。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"살아남는다면… 프로젝트의 큰 전환점이 되겠지.","JPN":"生き残れば……プロジェクトの大きなターニングポイントとなるだろう。","ENG":"If she lives... it will be a great turning point for the project.","TWN":"如果她能活下來……或許將成為計畫的重大轉捩點。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"…이리 와서 앉아라. B2-1.","JPN":"……ここに座れ。B2-1。","ENG":"...Come and sit down, B2-1.","TWN":"……過來坐下吧。B2-1。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"이제 뒤로 물러서.","JPN":"もう少し後ろに下がれ。","ENG":"Now, step back.","TWN":"現在退後。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"지금 기분이 어떻지?","JPN":"今の気分はどうだ？","ENG":"How do you feel?","TWN":"感覺怎麼樣？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"뜨겁지만… 견딜만해요.","JPN":"熱いですけど……耐えられそうです。","ENG":"A little hot, but... nothing I can't handle.","TWN":"雖然很熱……但還能忍受。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"앞으로도… 제가 주사 다 맞을 수 있어요.","JPN":"これからも……私に全部の注射を打ってください。","ENG":"I'll be able to... take all future injections.","TWN":"我還可以……打很多針的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"그러니… 그러니까…","JPN":"だから……だから……","ENG":"So... so...","TWN":"所以…… 所以說……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"우리 오빠는 건들지 말아주-","JPN":"お兄ちゃんには手を出さないでくー","ENG":"Please don't touch my broth–","TWN":"不要碰我哥哥——"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"컥…! 커헉…","JPN":"がっ……！　かっは……","ENG":"Kuh...! Urgh...","TWN":"咳……！咳咳……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"…회복하고 있군. 아주 인상적이야.","JPN":"……回復しているな。とてもすばらしい。","ENG":"…She's recovering. Impressive.","TWN":"……已經開始恢復了。真是印象深刻。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"B2-1. 일어서서 움직여봐라.","JPN":"B2-1。立ち上がって動いてみろ。","ENG":"B2-1. Get up and move around.","TWN":"B2-1。 站起來動一動。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"아파요…","JPN":"痛いです……","ENG":"It hurts...","TWN":"可是……好痛……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"일어서라. 어서.","JPN":"立て。早く。","ENG":"On your feet. Now.","TWN":"站起來，馬上。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"하아… 하…","JPN":"はあ……はぁ……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L30_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"폐를 관통했는데 벌써 숨을 쉴 정도로 회복하다니. 기대 이상의 결과야.","JPN":"肺を貫通したのに、もう息ができるほど回復するとは。期待以上の結果だ。","ENG":"It went right through her lungs, but she's already recovered enough to breathe. This is far beyond our expectations.","TWN":"肺都被穿透了，居然已經恢復到能呼吸的程度。我們獲得了超出預期的結果。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"다음은 뇌를 비롯한 급소부위의 재생 여부와 혈액 샘플의 효력 지속 시간을…","JPN":"次は脳を含む急所部位の再生可否と、血液サンプルの効力持続時間を……","ENG":"We should now test the regeneration of vital organs, including the brain, as well as the effect duration of the blood sample–","TWN":"接下來是關於大腦等重要部位的再生情況和血液樣本的效力持續時間……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"목이… 목이 타들어가…","JPN":"喉が……喉が渇いた……","ENG":"I need... something to drink...","TWN":"喉嚨……喉嚨有東西在燒……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L37_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"B2-1! 물러서! 지금 뭐하는 거냐!","JPN":"B2-1！　下がれ！　今何をしている！","ENG":"B2-1! Stand back! What do you think you're doing?!","TWN":"B2-1！退後！你現在在幹什麼！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"목 말라… 못 참겠어요!","JPN":"喉渇いた……もう我慢できません！","ENG":"I'm thirsty... I can't stand it!","TWN":"我……好渴……快忍不了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"빌어먹을! 상황실! 가스 살포해!","JPN":"くそっ！　緊急対応室！　ガスを散布しろ！","ENG":"Dammit! Situation room! Release the gas!","TWN":"該死！情況室！釋放毒氣！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"경비를 데려와! 저걸 제압하라고!","JPN":"警備を連れて来い！　あれを取り押さえるんだ！","ENG":"Bring the guards! Apprehend her!","TWN":"叫警衛來！快制服她！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L45_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"으아아아악!!!","JPN":"うああああ！！！","ENG":"AAAAARGH!!!","TWN":"啊啊啊啊啊！！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"실험 영상이라더니 스너프필름이 따로 없네요.","JPN":"実験映像っていうより、まるでスナッフフィルムですね。","ENG":"It says it's experiment footage, but it looks like a snuff film to me.","TWN":"與其說是實驗影片，不如說是虐殺……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 배경을 보니 지하시설에서 찍은 건 아닌 것 같아요.","JPN":"この背景を見ると、地下施設から撮ったものじゃないみたいです。","ENG":"Looking at the background, it doesn't look like it was filmed in the basement.","TWN":"看這個背景，似乎不是在地下設施拍的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"북방합의체의 몇몇 과학자들은 이상현상에 노출된 특이변이자들을 분석하는 실험을 계속 해왔죠.","JPN":"北方合意体の何人かの科学者は、異常現象に晒された特異変異者を分析する実験を続けてきました。","ENG":"Some of the scientists at the Northern Union have continued to conduct experiments to analyze strange mutants who have been exposed to abnormal phenomena.","TWN":"北方和議會的一些科學家，一直在進行分析暴露於異常現象的特異變異者的實驗。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"공식 통계는 없지만, 내부 정보에 따르면 이런 실험시설이 아직 많이 남아있을 겁니다.","JPN":"公式的な統計はありませんが、内部情報によりますとこんな実験施設がまだたくさん残っているはずです。","ENG":"Although there are no official statistics, intel from within suggests that there may still be many of these test facilities remaining.","TWN":"雖然沒有官方統計資料，但根據內部資訊，這樣的實驗設施可能還存在很多。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 실험복 차림의 아이는 낯이 익군.","JPN":"あの実験服姿の子どもは見覚えがあるな。","ENG":"That girl in the gown looks familiar.","TWN":"那個穿實驗服的孩子看起來很眼熟。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님도 그렇게 생각하십니까?","JPN":"最高管理者様もそう思いますか？","ENG":"Do you think so too, Administrator?","TWN":"管理者也這麼認為嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저도 비슷한 목소리와 인상을 가진 사람이 한 명 떠오르더군요.","JPN":"私も似たような声と顔の人物が1人だけ思い浮かびます。","ENG":"It reminded me of someone with a similar voice and facial structures as well.","TWN":"我也想起了一個聲音和面貌都很相似的人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…아마도 우연이겠죠. 그 사람은 북방합의체와 인연이 없으니까요.","JPN":"……おそらく偶然でしょう。あの人は北方合意体とは縁がないのですから。","ENG":"...It's probably a coincidence. For she had no ties with the Northern Union.","TWN":"……大概是巧合吧。那個人和北方和議會沒有什麼關係。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"영상의 뒷부분을 살펴본다","JPN":"映像の続きを見る","ENG":"Check the latter part of the video","TWN":"查看影片的後半部"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"영상 마지막 부분에 자막이 편집되어 있군.","JPN":"映像の最後の部分は字幕が編集されているな。","ENG":"The subtitles at the end seem to have been edited.","TWN":"影片最後部分的字幕有編輯過的痕跡。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마녀의 마당에 성난 그림자를 들이지 말 것</color>이라고 적혀있어.","JPN":"<color=#ffd34c>魔女の庭に激怒したシャドウを入れないこと</color>と書かれている。","ENG":"It says, <color=#ffd34c>\\"Do not bring angered Shadows into the witch's yard.\\"</color>","TWN":"<color=#ffd34c>不要讓憤怒的暗影進入女巫的花園</color>，上面是這麼寫的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"엉뚱한 영화 자막을 가져온 것 같네요.","JPN":"全く関係ない映画から字幕だけ抜き取ったみたいに見えます。","ENG":"It looks like they put in the wrong subtitles.","TWN":"看起來像是嵌入了莫名其妙的電影字幕……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니면 시니어가 저희에게 남긴 암호 같은 걸까요?","JPN":"それとも、シニアが私たちに残した暗号みたいなものでしょうか？","ENG":"Or could this be a cryptic message the Senior left for us?","TWN":"還是說這是Senior留給我們的密碼呢？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"의도는 모르겠지만, 그럴 가능성도 배제할 순 없겠지.","JPN":"意図はわからないが、その可能性も排除できないな。","ENG":"Without knowing what the intent was, we cannot rule out that possibility.","TWN":"在對方意圖不明的情況下，也不能排除這種可能性。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"영상의 타이틀을 확인한다","JPN":"映像のタイトルを確認する","ENG":"Check the title of the video","TWN":"確認影片標題"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 영상들의 제목에 들어간 숫자들이 영상의 순서를 의미하는 것 같진 않군.","JPN":"この映像たちのタイトルに入った数字は、映像の順番を意味しているのではないようだ。","ENG":"I don't think the numbering in the titles of the videos indicates the order to watch them.","TWN":"影片標題中的數字似乎並不代表影片的順序。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 제목들을 편집 된 날짜 순으로 정렬해보면…","JPN":"だが、このタイトルを編集された日付順に並べると……","ENG":"But if we sort the titles by their last edited date...","TWN":"但是如果按編輯日期排列的話……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이건…? 차원항로 좌표군요.","JPN":"これは……？　次元航路の座標ですね。","ENG":"These are... coordinates to a dimensional route.","TWN":"這是……？次元航路座標。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 아주 수상하지만, 이게 유일한 힌트라고 생각하면 무시하기 힘들군.","JPN":"ああ。とても怪しいが、これが唯一のヒントだと思うと無視することはできない。","ENG":"Yes. It's strange, but it's hard to ignore it considering it's our only hint.","TWN":"是啊，雖然很可疑，但考慮到這是唯一的線索，就很難忽視了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고심도 좌표로 보이는데, 차원함선이 없으니 확인은 어렵겠어.","JPN":"高深度の座標に見えるが、次元艦船がないと確認することは難しいだろう。","ENG":"It looks like hyperdepths coordinates, but it's hard to confirm without a dimensional ship.","TWN":"看起來是高深度座標，但沒有次元艦船，難以確認。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"찾아낸 실험 영상들은 모두 증거 자료로 확보해주게.","JPN":"見つけた実験の映像はすべて証拠資料として確保してくれたまえ。","ENG":"Collect and secure all the test videos you've found as evidence.","TWN":"麻煩將找到的實驗影片作為證據資料保存好。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"Understood.","TWN":"明白了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"찾아낸 좌표도 관리국에 분석을 맡겨보죠.","JPN":"見つけた座標も管理局に分析を依頼してみましょう。","ENG":"I'll leave the analysis of the coordinates to the Administration.","TWN":"我把找到的座標也交給管理局分析吧。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 흩어져서 다시 잭슨의 흔적을 찾아보기로…","JPN":"では、もう1度手分けしてジャクソンの跡を……","ENG":"Then, let's split up again and look for traces of Jackson...","TWN":"那麼，我們分頭行動，繼續尋找傑森的蹤跡……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠시만요. 뭔가 안 좋은 게 느껴져요.","JPN":"待ってください。なんか良くない感じがするんです。","ENG":"Hold on. Something doesn't feel right.","TWN":"等等。我總感覺有不好的東西……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안 좋은 것? 유령의 시선 같은 건가?","JPN":"良くない感じ？　幽霊を感じるとかか？","ENG":"Doesn't feel right? Are you sensing a ghost's gaze?","TWN":"不好的東西？像是幽靈的視線之類的？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하… 그건 아니겠네요.","JPN":"はは……それは違いますね。","ENG":"Haha... Nothing like that.","TWN":"哈哈……那倒不是……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"유령은 땅이 울릴 정도로 뛰어다니지 않거든요.","JPN":"幽霊は地鳴りがするほど走り回ったりしませんよ。","ENG":"Because ghosts don't make the ground shake by running.","TWN":"幽靈跑起來可不會讓地面震動。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"대형 침식체 다수 확인.","JPN":"大型の侵食体を多数確認。","ENG":"Multiple large C.O.s detected.","TWN":"確認到多個大型侵蝕體。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저희가 처리할 테니, 관리자님은 잠시 물러서시길.","JPN":"私たちで処理しますので、最高管理者様はしばらく下がっていてください。","ENG":"We'll deal with them, so please step back, Administrator.","TWN":"交給我們，管理者請稍微退後一點。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};